 1	import { FormGroup, Title, Button, Modal, Label, LabelGroup } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import AddLimitModal from './AddLimitModal';
 4	import { LimitConfig } from './types';
 5	import { useTranslation } from 'react-i18next';
 6	
 7	interface LimitSelectProps {
 8	  limits: Record<string, LimitConfig>;
 9	  setLimits: React.Dispatch<React.SetStateAction<Record<string, LimitConfig>>>;
10	}
11	
12	const LimitSelect: React.FC<LimitSelectProps> = ({ limits, setLimits }) => {
13	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
14	  const [isAddLimitModalOpen, setIsAddLimitModalOpen] = React.useState(false);
15	  const [isLimitNameAlertModalOpen, setIsLimitNameAlertModalOpen] = React.useState(false);
16	  const [newLimit, setNewLimit] = React.useState<LimitConfig>({
17	    rates: [{ duration: 60, limit: 100, unit: 'minute' }],
18	  });
19	  const [rateName, setRateName] = React.useState<string>('');
20	
21	  const handleOpenModal = () => {
22	    setNewLimit({ rates: [{ duration: 60, limit: 100, unit: 'minute' }] });
23	    setRateName('');
24	    setIsAddLimitModalOpen(true);
25	  };
26	
27	  const handleCloseModal = () => setIsAddLimitModalOpen(false);
28	
29	  const onAddLimit = () => {
30	    if (!rateName) {
31	      setIsLimitNameAlertModalOpen(true);
32	      return;
33	    }
34	
35	    setLimits((prevLimits) => ({
36	      ...prevLimits,
37	      [rateName]: newLimit,
38	    }));
39	
40	    handleCloseModal();
41	  };
42	
43	  const handleRemoveLimit = (name: string) => {
44	    setLimits((prevLimits) => {
45	      const updatedLimits = { ...prevLimits };
46	      delete updatedLimits[name];
47	      return updatedLimits;
48	    });
49	  };
50	
51	  return (
52	    <>
53	      <FormGroup>
54	        <Title headingLevel="h2" size="lg" className="kuadrant-limits-header">
55	          {t('Configured Limits')}
56	        </Title>
57	        <LabelGroup numLabels={5}>
58	          {Object.keys(limits).length > 0 ? (
59	            Object.entries(limits).map(([name, limitConfig], index) => (
60	              <Label key={index} color="blue" onClose={() => handleRemoveLimit(name)}>
61	                <strong>{name}</strong>: {limitConfig.rates?.[0]?.limit} requests per{' '}
62	                {limitConfig.rates?.[0]?.duration} {limitConfig.rates?.[0]?.unit}(s)
63	              </Label>
64	            ))
65	          ) : (
66	            <p>{t('No limits configured yet')}</p>
67	          )}
68	        </LabelGroup>
69	        <Button variant="primary" onClick={handleOpenModal} className="kuadrant-limits-button">
70	          {t('Add Limit')}
71	        </Button>
72	      </FormGroup>
73	      {/* Modal to add a new limit */}
74	      <AddLimitModal
75	        isOpen={isAddLimitModalOpen}
76	        onClose={handleCloseModal}
77	        newLimit={newLimit}
78	        setNewLimit={setNewLimit}
79	        rateName={rateName}
80	        setRateName={setRateName}
81	        handleSave={onAddLimit}
82	      />
83	      <Modal
84	        title="Validation Error"
85	        isOpen={isLimitNameAlertModalOpen}
86	        onClose={() => setIsLimitNameAlertModalOpen(false)}
87	        variant="small"
88	        aria-label="Rate Name is required error"
89	      >
90	        <p>{t('Limit Name is required!')}</p>
91	        <Button variant="primary" onClick={() => setIsLimitNameAlertModalOpen(false)}>
92	          {t('OK')}
93	        </Button>
94	      </Modal>
95	    </>
96	  );
97	};
98	
99	export default LimitSelect;

